import { Action } from 'redux';
import createReducer from '~/redux/store/createReducer';
import { InvoiceDetailsRequest } from '../sagas/invoices/details';
import { TransactionResume } from '../sagas/invoices/Models/invoice';

export enum InvoiceTypes {
  REQUEST_FINTECH_INVOICE = '@invoice/REQUEST_FINTECH_INVOICE',
  SUCCESS_FINTECH_INVOICE = '@invoice/SUCCESS_FINTECH_INVOICE',
  FAILED_FINTECH_INVOICE = '@invoice/FAILED_FINTECH_INVOICE',
  CLEAN = '@invoice/CLEAN',
  REQUEST_FINTECH_INVOICE_DETAILS = '@invoice/REQUEST_FINTECH_INVOICE_DETAILS',
  CANCEL_REQUEST_FINTECH_INVOICE = '@invoice/CANCEL_REQUEST_FINTECH_INVOICE',
}

export type invoiceCellType = 'physicalCard' | 'virtualCard' | 'tag' | 'others';

export interface InvoiceResponse {
  code: number;
  message: string;
  data: {
    Taxas: {
      RotativoMensal: number;
      RotativoAnual: number;
      RotativoProx: number;
    };
    TotalPagamentoFaturaAnterior: number;
    ValorFaturaAtual: number;
    ValorPagamentoMinimo: number;
    ValorFaturaAnterior: number;
    MelhorDiaCompra: string;
    DataFechamento: string;
    DataVencimento: string;
    CartaoCredito: {
      Cartao: string;
      Compras: {
        Sequencia: number;
        Data: string;
        Descricao: string;
        Parcela: number;
        TotalParcelas: number;
        ValorOriginalTransacao: number;
        ValorTransacao: number;
        Tipo: string;
        Moeda: string;
        CodigoTransacao: number;
        FormaDeCaptura: number | null;
        NumeroReferencia: string;
        TaxaConversaoDolar: number;
        CodigoMoedaOrigem?: string;
        ValorTransacaoDolar?: number;
        Estabelecimento?: string;
        Veiculo?: {
          Placa?: string;
        };
      }[];
    }[];
  };
}

export interface InvoiceObj {
  title: string;
  description: string;
  date: string;
  type: invoiceCellType;
  value: string;
  fullValue: number;
  items: Record<string, TransactionResume[]>;
}

export type InvoicesData = {
  [invoiceDate: string]: InvoiceObj[];
};

export interface InvoiceReducerProps {
  isLoading: boolean;
  isError: boolean;
  invoicesExtract: InvoicesData | undefined;
}

type State = InvoiceReducerProps;

const initialState: InvoiceReducerProps = {
  isLoading: false,
  isError: false,
  invoicesExtract: undefined,
};

const invoiceFintechReducer = createReducer(initialState, {
  [InvoiceTypes.REQUEST_FINTECH_INVOICE](state: State): State {
    return {
      ...state,
      isLoading: true,
    };
  },
  [InvoiceTypes.SUCCESS_FINTECH_INVOICE](
    state: State,
    {
      data,
    }: {
      data: InvoicesData;
    },
  ): State {
    return {
      ...state,
      isLoading: false,
      isError: false,
      invoicesExtract: data,
    };
  },
  [InvoiceTypes.FAILED_FINTECH_INVOICE](state: State): State {
    return {
      ...state,
      isLoading: false,
      isError: true,
    };
  },
  [InvoiceTypes.CANCEL_REQUEST_FINTECH_INVOICE](state: State): State {
    return {
      ...state,
      isLoading: false,
    };
  },
  [InvoiceTypes.CLEAN](): State {
    return initialState;
  },
});

interface InvoiceActions {
  invoiceFintechRequest: (date: string) => Action;
  invoiceFintechSuccess: (data: InvoicesData) => Action;
  invoiceFintechClean: () => Action;
  invoiceFintechError: () => Action;
  invoiceDetailsFintechRequest: ({
    id,
    callback,
  }: InvoiceDetailsRequest) => Action;
  invoiceCancelRequest: () => Action;
}

export const invoiceFintechActions: InvoiceActions = {
  invoiceFintechRequest: (date: string) => ({
    type: InvoiceTypes.REQUEST_FINTECH_INVOICE,
    date,
  }),
  invoiceFintechSuccess: (data: InvoicesData) => ({
    type: InvoiceTypes.SUCCESS_FINTECH_INVOICE,
    data,
  }),
  invoiceFintechClean: () => ({
    type: InvoiceTypes.CLEAN,
  }),
  invoiceFintechError: () => ({
    type: InvoiceTypes.FAILED_FINTECH_INVOICE,
  }),
  invoiceDetailsFintechRequest: ({ id, callback }: InvoiceDetailsRequest) => ({
    type: InvoiceTypes.REQUEST_FINTECH_INVOICE_DETAILS,
    id,
    callback,
  }),
  invoiceCancelRequest: () => ({
    type: InvoiceTypes.CANCEL_REQUEST_FINTECH_INVOICE,
  }),
};

export default invoiceFintechReducer;

