  totalBillValue: number;
  billStatus: number;
  billStatusDescription: string;
  bankReturnStatus: number;
  centralizedCodeOfBankReturnOccurrence: string;
  collectionAgreementStatus: number;
  billIssuanceFlag: boolean;
  settledAmount: number;
