      value: number;
      quantity: number;
    };
  };
};

export interface GetSPInvoiceResponse {
  desc: {
    url: string;
  };
}

export interface InvoicesListFintechResponse {
  serviceMessage: {
    codigoRetorno: number;
  };
  billSummaryList: BillItem[];
  billAgreementList: [];
  agreementList: [];
}

export interface InvoicesListFintechProps {
  isLoading: boolean;
  isPDFLoading: boolean;
  isError: boolean;
  isPDFError: boolean;
  tagInvoices: InvoicesListFintechResponse;
  previousInvoices: Record<string, PreviousInvoice[]>;
}

type State = InvoicesListFintechProps;

export const initialState: InvoicesListFintechProps = {
  isLoading: false,
  isPDFLoading: false,
  isError: false,
  isPDFError: false,
  tagInvoices: {
    serviceMessage: {
      codigoRetorno: 0,
    },
    billSummaryList: [],
    billAgreementList: [],
    agreementList: [],
  },
  previousInvoices: {},
};

const invoicesListFintechReducer = createReducer(initialState, {
  [InvoicesListTypes.REQUEST_FINTECH_INVOICES_LIST](state: State): State {
    return {
      ...state,
      isLoading: true,
    };
  },
  [InvoicesListTypes.REQUEST_FINTECH_INVOICE_PDF](state: State): State {
    return {
      ...state,
      isPDFLoading: true,
    };
  },
  [InvoicesListTypes.SUCCESS_FINTECH_INVOICE_PDF](state: State): State {
    return {
      ...state,
      isPDFError: false,
      isPDFLoading: false,
    };
  },
  [InvoicesListTypes.SUCCESS_FINTECH_INVOICES_LIST](
    state: State,
    {
      data: { tagInvoices, previousInvoices },
    }: {
      data: {
        tagInvoices: InvoicesListFintechProps['tagInvoices'];
        previousInvoices: InvoicesListFintechProps['previousInvoices'];
      };
    },
  ): State {
    return {
      ...state,
      isLoading: false,
      isError: false,
      isPDFError: false,
      tagInvoices,
      previousInvoices,
    };
  },
  [InvoicesListTypes.FAILED_FINTECH_INVOICES_LIST](state: State): State {
    return {
      ...state,
      isLoading: false,
      isError: true,
    };
  },
  [InvoicesListTypes.FAILED_FINTECH_INVOICE_PDF](state: State): State {
    return {
      ...state,
      isPDFLoading: false,
      isPDFError: true,
    };
  },
  [InvoicesListTypes.CLEAN_FINTECH_INVOICES_LIST](): State {
    return initialState;
  },
  [InvoicesListTypes.CLEAN_FINTECH_INVOICE_PDF](state: State): State {
    return {
      ...state,
      isPDFError: false,
      isPDFLoading: false,
    };
  },
});

interface InvoicesListFintechActions {
  invoicesListFintechRequest: () => Action;
  invoicePDFFintechRequest: (data: { invoiceNumber: string }) => Action;
  invoicePDFFintechSuccess: () => Action;
  invoicesListFintechSuccess: (data: {
    tagInvoices: InvoicesListFintechProps['tagInvoices'];
    previousInvoices: InvoicesListFintechProps['previousInvoices'];
  }) => Action;
  invoicesListFintechClean: () => Action;
  invoicePDFFintechClean: () => Action;
  invoicesListFintechError: () => Action;
  invoicePDFFintechError: () => Action;
}

export const invoicesListFintechActions: InvoicesListFintechActions = {
  invoicesListFintechRequest: () => ({
    type: InvoicesListTypes.REQUEST_FINTECH_INVOICES_LIST,
  }),
  invoicePDFFintechRequest: data => ({
    type: InvoicesListTypes.REQUEST_FINTECH_INVOICE_PDF,
    data,
  }),
  invoicePDFFintechSuccess: () => ({
    type: InvoicesListTypes.SUCCESS_FINTECH_INVOICE_PDF,
  }),
  invoicesListFintechSuccess: data => ({
    type: InvoicesListTypes.SUCCESS_FINTECH_INVOICES_LIST,
    data,
  }),
  invoicesListFintechError: () => ({
    type: InvoicesListTypes.FAILED_FINTECH_INVOICES_LIST,
  }),
  invoicePDFFintechError: () => ({
    type: InvoicesListTypes.FAILED_FINTECH_INVOICE_PDF,
  }),
  invoicesListFintechClean: () => ({
    type: InvoicesListTypes.CLEAN_FINTECH_INVOICES_LIST,
  }),
  invoicePDFFintechClean: () => ({
    type: InvoicesListTypes.CLEAN_FINTECH_INVOICE_PDF,
  }),
};

export default invoicesListFintechReducer;

